import { useEffect, useMemo, useState } from "react"
import { Card, Row, Col, Badge } from "react-bootstrap";
import { api } from "../api";

export default function Dashboard() {

  const [me, setMe] = useState(null);
  const [workouts, setWorkouts] = useState([]);
  const [err, setErr] = useState("");

  // Here I am loading the current user and some of their recentmost workouts
  useEffect(() => {
    api("/auth/status")
      .then((resp) => {
        if (resp && resp.user) {
          setMe(resp.user);
        } else {
          setMe(null);
        }
      })
      .catch(() => setMe(null));
    
    // These are my workouts
    api("/workouts")
      .then((workouts) => {
        const list = Array.isArray(workouts) ? workouts : workouts?.items || [];

        // Here I am sorting the workouts as per timestamp, keeping the newest ones first
        list.sort((a, b) => {
          const date_a = a.date || "";
          const date_b = b.date || "";
          if (date_a === date_b) {
            return (b.created_at || "").localeCompare(a.created_at || "");
          }
          return date_b.localeCompare(date_a);
        });
        setWorkouts(list);
      })
      .catch((e) => {
        console.error(e);
        setErr("Could not load your workouts.");
        setWorkouts([]);
      });
  }, []);

  // These are helper functions created for calculating dashboard based statistics
  function parseDate(d) {
    if (!d) return null;
    const [y, m, day] = d.split("-").map(Number);
    if (!y || !m || !day) return null;
    return new Date(y, m - 1, day);
  }

  const {
    totalWorkouts,
    lastWorkout,
    weeklyMinutes,
    weeklyCount,
    weeklyDaysTrained,
  } = useMemo(() => {
    if (!workouts || workouts.length === 0) {
      return {
        totalWorkouts: 0,
        lastWorkout: null,
        weeklyMinutes: 0,
        weeklyCount: 0,
        weeklyDaysTrained: 0,
      };
    }

    const today = new Date();
    const sevenDaysAgo = new Date(
      today.getFullYear(),
      today.getMonth(),
      today.getDate() - 6
    );

    let weeklyMinutes = 0;
    let weeklyCount = 0;
    const weeklyDates = new Set();

    for (const w of workouts) {
      const d = parseDate(w.date);
      if (!d) continue;

      if (d >= sevenDaysAgo && d <= today) {
        weeklyMinutes += Number(w.duration_minutes || 0);
        weeklyCount += 1;
        weeklyDates.add(w.date);
      }
    }

    return {
      totalWorkouts: workouts.length,
      lastWorkout: workouts[0] || null,
      weeklyMinutes: weeklyMinutes,
      weeklyCount: weeklyCount,
      weeklyDaysTrained: weeklyDates.size,
    };
  }, [workouts]);

  return (
    <div className="dashboard-page py-3">
      <div className="d-flex justify-content-between align-items-baseline mb-3">
        <div>
          <h1 className="mb-1">Dashboard</h1>
          <p className="text-muted mb-0 small">Quick snapshot of your ShreddedNerds grind.</p>
        </div>
        {me && (
          <div className="text-end small text-muted">
            Signed in as <strong>{me.username}</strong>
          </div>
        )}
      </div>

      {err && (
        <div className="alert alert-danger py-2" role="alert">
          {err}
        </div>
      )}

      <Row className="mb-3">
        {/* Weekly minutes */}
        <Col md={4} className="mb-3">
          <Card className="dashboard-card shadow-sm h-100">
            <Card.Body>
              <Card.Title as="h5" className="mb-1">This week at the SRC</Card.Title>
              <Card.Subtitle className="mb-2 text-muted small">Last 7 days</Card.Subtitle>

              <div className="display-6 fw-semibold mb-1">
                {weeklyMinutes} <span className="fs-6">min</span>
              </div>
              <p className="small text-muted mb-2">
                {weeklyCount === 0
                  ? "No sessions logged yet this week."
                  : `Across ${weeklyCount} workout${
                      weeklyCount === 1 ? "" : "s"
                    } on ${weeklyDaysTrained} day${
                      weeklyDaysTrained === 1 ? "" : "s"
                    }.`}
              </p>

              <div className="progress" style={{ height: 6 }}>
                <div className="progress-bar bg-maroon" role="progressbar"
                  style={{ width: `${Math.min(100, Math.round((weeklyMinutes / 300) * 100))}%`}}
                  aria-valuenow={weeklyMinutes}
                  aria-valuemin={0}
                  aria-valuemax={300}
                ></div>
              </div>
              <p className="small text-muted mt-1 mb-0">
                Goal example: 300 minutes / week (~5 hours).
              </p>
            </Card.Body>
          </Card>
        </Col>

        {/* Total workouts + streak-ish */}
        <Col md={4} className="mb-3">
          <Card className="dashboard-card shadow-sm h-100">
            <Card.Body>
              <Card.Title as="h5" className="mb-1">All-time sessions</Card.Title>
              <Card.Subtitle className="mb-2 text-muted small">Since you joined ShreddedNerds</Card.Subtitle>

              <div className="display-6 fw-semibold mb-1">{totalWorkouts}</div>

              <p className="small text-muted mb-2">
                {totalWorkouts === 0
                  ? "Log your first workout to start your history."
                  : "Every logged session powers your dashboards and leaderboards."}
              </p>

              {weeklyDaysTrained > 0 && (
                <div className="small">
                  <Badge bg="light" text="dark" className="border me-1">
                    Active this week
                  </Badge>
                  <span className="text-muted">{weeklyDaysTrained} training day{weeklyDaysTrained === 1 ? "" : "s"} so far.</span>
                </div>
              )}
            </Card.Body>
          </Card>
        </Col>

        {/* Last workout */}
        <Col md={4} className="mb-3">
          <Card className="dashboard-card shadow-sm h-100">
            <Card.Body>
              <Card.Title as="h5" className="mb-1">Last workout</Card.Title>
              <Card.Subtitle className="mb-2 text-muted small">Quick recap</Card.Subtitle>

              {!lastWorkout ? (
                <p className="small text-muted mb-0">
                  You haven&apos;t logged a workout yet. Head to{" "}
                  <strong>Log Workouts</strong> to record your first SRC
                  session.
                </p>
              ) : (
                <>
                  <div className="fw-semibold mb-1">
                    {lastWorkout.date} · {lastWorkout.duration_minutes} min
                  </div>
                  <p className="small text-muted mb-2">
                    {lastWorkout.notes
                      ? lastWorkout.notes
                      : "No notes added for this workout."}
                  </p>
                  <p className="small mb-0 text-muted">
                    Your detailed breakdown is available on the{" "}
                    <strong>History</strong> page (coming soon) and in the
                    Workouts section.
                  </p>
                </>
              )}
            </Card.Body>
          </Card>
        </Col>
      </Row>

      {/* Recent mini list at bottom */}
      <Row>
        <Col md={8}>
          <Card className="dashboard-card shadow-sm">
            <Card.Body>
              <Card.Title as="h5" className="mb-2">
                Recent workouts
              </Card.Title>
              <p className="small text-muted">
                A quick glance at your last few sessions.
              </p>

              {workouts.length === 0 && (
                <p className="small text-muted mb-0">
                  Nothing here yet — log a workout to see it appear.
                </p>
              )}

              {workouts.slice(0, 5).map((w) => (
                <div
                  key={w.id}
                  className="d-flex justify-content-between small mb-2"
                >
                  <div>
                    <div className="fw-semibold">{w.date}</div>
                    <div className="text-muted">
                      {w.duration_minutes} min
                      {w.notes ? ` · ${w.notes.slice(0, 40)}…` : ""}
                    </div>
                  </div>
                  <div className="text-end text-muted">
                    <div>ID #{w.id}</div>
                  </div>
                </div>
              ))}
            </Card.Body>
          </Card>
        </Col>

        <Col md={4} className="mt-3 mt-md-0">
          <Card className="dashboard-card shadow-sm h-100">
            <Card.Body className="small text-muted">
              <Card.Title as="h6" className="mb-2">
                How this dashboard works
              </Card.Title>
              <ul className="mb-0 ps-3">
                <li>All stats are computed from your logged workouts.</li>
                <li>
                  &ldquo;This week&rdquo; means today plus the previous 6 days.
                </li>
                <li>
                  Every new session updates this page, your history, and (later)
                  leaderboards.
                </li>
              </ul>
            </Card.Body>
          </Card>
        </Col>
      </Row>
    </div>
  );
}